var (
	// Version information, injected at build time
	Version   = "dev"
	GitCommit = "unknown"
	BuildTime = "unknown"
	// BasePath is the URL path prefix, injected at build time
	// Empty string means deploy at root path, e.g. "rainbow-bridge" means /rainbow-bridge
	BasePath = ""
)

func main() {
	configPath := flag.String("config", "config.yaml", "path to config file")
	noFrontend := flag.Bool("no-frontend", false, "disable frontend static files")
	flag.Parse()

	// 先加载配置文件，获取 base_path
	cfg, err := LoadConfig(*configPath)
	if err != nil {
		log.Printf("Warning: failed to load config: %v, will use default config", err)
	}

	// 优先级：配置文件 > 环境变量 > 编译时参数
	effectiveBasePath := ""
	if cfg != nil && cfg.Server.BasePath != "" {
		effectiveBasePath = cfg.Server.BasePath
		log.Printf("Using BASE_PATH from config file: %s", effectiveBasePath)
	} else if envBasePath := os.Getenv("BASE_PATH"); envBasePath != "" {
		effectiveBasePath = envBasePath
		log.Printf("Using BASE_PATH from environment: %s", effectiveBasePath)
	} else if BasePath != "" {
		effectiveBasePath = BasePath
		log.Printf("Using BASE_PATH from build time: %s", BasePath)
	}

	application, err := Initialize(*configPath, BuildConfig{
		Version:   Version,
		GitCommit: GitCommit,
		BuildTime: BuildTime,
		BasePath:  effectiveBasePath,
	})
	if err != nil {
		log.Fatalf("initialize app: %v", err)
	}

	// Serve embedded frontend static files if not disabled
	if !*noFrontend {
		setupStaticFileServer(application.H, application.BasePath)
		log.Printf("Full application listening at %s (with frontend)", application.Config.Server.Address)
	} else {
		log.Printf("API server listening at %s (no frontend)", application.Config.Server.Address)
	}

	if application.BasePath != "" {
		log.Printf("Server base path: %s", application.BasePath)
	}

	application.H.Spin()
}

func setupStaticFileServer(h *server.Hertz, basePath string) {
	webFS, err := static.WebFS()
	if err != nil {
		log.Printf("Warning: failed to load web files: %v", err)
		return
	}

	useEmbed := static.UseEmbedFS()
	if useEmbed {
		log.Printf("Serving static files from embedded filesystem")
	} else {
		log.Printf("Serving static files from filesystem (dev mode)")
	}

	staticHandler := func(c context.Context, ctx *app.RequestContext) {
		path := string(ctx.URI().Path())

		// 去除 basePath 前缀（如果存在）
		if basePath != "" {
			path = strings.TrimPrefix(path, basePath)
		}

		// 如果路径以 /api/ 开头，跳过静态文件处理，让请求继续被 API 路由处理
		if strings.HasPrefix(path, "/api/") {
			ctx.Next(c)
			return
		}

		// 处理路径
		if path == "" || path == "/" {
			path = "/index.html"
		}

		if !strings.HasPrefix(path, "/") {
			path = "/" + path
		}

		if ext := filepath.Ext(path); ext == "" && path != "/index.html" {
			path = "/index.html"
		}

		// Clean path without leading "/"
		fsPath := strings.TrimPrefix(path, "/")
		content, err := fs.ReadFile(webFS, fsPath)
		if err != nil {
			ctx.Status(404)
			return
		}

		contentType := getContentType(path)
		ctx.Data(200, contentType, content)
	}

	// 处理所有GET请求，优先尝试静态文件
	h.GET("/*filepath", staticHandler)
	h.HEAD("/*filepath", staticHandler)

	// 处理404请求
	noRoute := func(c context.Context, ctx *app.RequestContext) {
		path := string(ctx.URI().Path())

		// 去除 basePath 前缀（如果存在）
		if basePath != "" {
			path = strings.TrimPrefix(path, basePath)
		}

		// 如果路径以 /api/ 开头，返回404
		if strings.HasPrefix(path, "/api/") {
			ctx.Status(404)
			ctx.JSON(404, map[string]string{"error": "not found"})
			return
		}

		// 否则返回index.html（用于SPA路由）
		data, err := fs.ReadFile(webFS, "index.html")
		if err != nil {
			ctx.Status(404)
			return
		}

		ctx.Data(200, "text/html; charset=utf-8", data)
	}

	h.NoRoute(noRoute)
}

func getContentType(path string) string {
	switch filepath.Ext(path) {
	case ".html":
		return "text/html; charset=utf-8"
	case ".css":
		return "text/css; charset=utf-8"
	case ".js":
		return "application/javascript; charset=utf-8"
	case ".json":
		return "application/json; charset=utf-8"
	case ".png":
		return "image/png"
	case ".jpg", ".jpeg":
		return "image/jpeg"
	case ".svg":
		return "image/svg+xml"
	case ".ico":
		return "image/x-icon"
	case ".woff", ".woff2":
		return "font/woff2"
	case ".ttf":
		return "font/ttf"
	default:
		return "application/octet-stream"
	}
}
